-- Выбрать конкретные поля
SELECT name, age FROM users;

-- Выбрать все поля
SELECT * FROM products;

-- Переименовать столбцы в результате
SELECT name AS product_name, price AS cost FROM products;

-- Простое сравнение
SELECT * FROM users WHERE age > 18;

-- Диапазон значений
SELECT * FROM products WHERE price BETWEEN 100 AND 500;

-- Поиск по шаблону (имена, начинающиеся на 'А')
SELECT * FROM users WHERE name LIKE 'А%';

-- Несколько условий
SELECT * FROM orders WHERE status = 'active' AND amount > 1000;

-- Список значений
SELECT * FROM products WHERE category IN ('электроника', 'гаджеты');

-- Проверка на NULL
SELECT * FROM users WHERE phone IS NULL;

-- По убыванию возраста
SELECT * FROM users ORDER BY age DESC;

-- По цене от дешёвых к дорогим
SELECT name, price FROM products ORDER BY price ASC;

-- Сначала по категории, потом по цене внутри категории
SELECT * FROM products ORDER BY category ASC, price DESC;

-- Количество товаров в каждой категории
SELECT category, COUNT(*) AS qty FROM products GROUP BY category;

-- Сумма заказов каждого пользователя
SELECT user_id, SUM(amount) AS total FROM orders GROUP BY user_id;

-- Средняя цена по категориям
SELECT category, AVG(price) AS avg_price FROM products GROUP BY category;

-- Максимальный заказ каждого пользователя
SELECT user_id, MAX(amount) AS max_order FROM orders GROUP BY user_id;

-- В WHERE: товары дороже средней цены
SELECT * FROM products
WHERE price > (SELECT AVG(price) FROM products);

-- В FROM: средняя цена по категориям
SELECT t.category, t.avg_price
FROM (
  SELECT category, AVG(price) AS avg_price
  FROM products
  GROUP BY category
) AS t;

-- IN: пользователи, у которых есть заказы
SELECT * FROM users
WHERE id IN (SELECT DISTINCT user_id FROM orders);

-- Добавить одну запись
INSERT INTO users (name, age) VALUES ('Иван', 25);

-- Добавить несколько сразу
INSERT INTO users (name, age) VALUES ('Мария', 30), ('Пётр', 22);

-- Обновить один столбец
UPDATE users SET age = 26 WHERE id = 1;

-- Обновить несколько столбцов
UPDATE users SET age = 26, name = 'Иван П.' WHERE id = 1;

-- Удалить конкретную запись
DELETE FROM users WHERE id = 1;

-- Удалить по условию
DELETE FROM orders WHERE status = 'cancelled' AND created_at < '2023-01-01';

-- Индекс для поиска по email
CREATE INDEX idx_users_email ON users(email);

-- Индекс для JOIN по user_id
CREATE INDEX idx_orders_user ON orders(user_id);

-- Уникальный индекс (email не должен повторяться)
CREATE UNIQUE INDEX idx_unique_email ON users(email);

-- Составной индекс
CREATE INDEX idx_orders_user_date ON orders(user_id, created_at);

-- Удалить индекс
DROP INDEX idx_users_email;

-- Банковский перевод
BEGIN;
UPDATE accounts SET balance = balance - 500 WHERE id = 1;
UPDATE accounts SET balance = balance + 500 WHERE id = 2;
COMMIT;

-- С обработкой ошибки (псевдокод)
BEGIN;
UPDATE accounts SET balance = balance - 500 WHERE id = 1;
-- если что-то пошло не так:
ROLLBACK;
-- если всё хорошо:
COMMIT;

-- SAVEPOINT
BEGIN;
INSERT INTO orders (user_id, amount) VALUES (1, 1000);
SAVEPOINT after_insert;
UPDATE products SET stock = stock - 1 WHERE id = 5;
ROLLBACK TO after_insert; -- отменяем только UPDATE
COMMIT; -- INSERT сохраняется

